SELECT YYYYMM,SEL_CODE,SITE,ACCT_CLASS,계정과목내부코드,전표기표여부,ACCT,ACCT_NAME,차대,계정대분류,관리항목유형,계정과목Lev,상위계정과목,경영계획과목,상위계정과목내부코드,소분류,중분류,대분류,expen_sel,expen_sel명,특이사항
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYYMM, SITE, ACCT) max_seq_no FROM #TempTable
)A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_ACCT b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SITE = a.SITE
	AND b.ACCT = a.ACCT
);

