INSERT INTO DOI_BOM_MAST (YYYYMM,SITE,제품명,제품번호,품목자산분류,품목대분류,품목중분류,품목소분류,공정차수,공정,공정품명,공정품번호,자재명,자재번호,자재자산분류,자재대분류,자재중분류,자재소분류,투입단위,소요량,내부Loss율,외부Loss율,조립위치,특이사항,최초작성일,최초작성자,최종수정일,최종수정자 )
SELECT YYYYMM,SITE,제품명,제품번호,품목자산분류,품목대분류,품목중분류,품목소분류,공정차수,공정,공정품명,공정품번호,자재명,자재번호,자재자산분류,자재대분류,자재중분류,자재소분류,투입단위,
소요량,내부Loss율,외부Loss율,조립위치,특이사항,최초작성일,최초작성자,최종수정일,최종수정자
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYYMM, SITE, 제품번호, 공정, 자재번호) max_seq_no FROM #TempTable
)A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_BOM_MAST b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SITE = a.SITE
	AND b.제품번호 = a.제품번호
	AND b.공정 = a.공정
	AND b.자재번호 = a.자재번호
);

DROP TABLE #TempTable;

mapper.select:
SELECT COUNT(*) AS cnt
FROM DOI_BOM_MAST
WHERE yyyymm = #{yyyymm}
  AND site   = #{site}

select YYYYMM, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' Then '본사' WHEN SITE='VN' then 'VINA' else site end as SITE, MODEL, SPEC, INCH, GLASS_THICK, SHEET, BLOCK, CELL, RUN_SIZE, X, Y, XY, ADD_YN from DOI_MODEL_MAST where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
and sel_code = #{selCode}
order BY MODEL;

mapper.update:
		UPDATE DOI_MODEL_MAST
		SET SEL_CODE = #{selCode}
  		,SPEC        = #{spec}
		,INCH        = CAST(#{inch} as real)NULL
		,GLASS_THICK = CAST(#{glassThick} as real)NULL
		,SHEET       = CAST(#{sheet} as real)NULL
		,BLOCK       = CAST(#{block} as real)NULL
		,CELL        = CAST(#{cell} as real)NULL
		,RUN_SIZE    = CAST(#{runSize} as real)NULL
		,X = CAST(#{x} as real)NULL
		,Y = CAST(#{y} as real)NULL
		,XY = CAST(#{xy} as numeric(38,25))NULL
		WHERE 1=1
		and yyyymm = #{yyyymm}
		and site = #{siteOrg}
		and model = #{model}
		;

mapper.delete:
